mapper.select:
SELECT s.id , s.name AS student_name, u.mobile AS phone, s.gender AS gender, c.name AS default_course, (sc.count_lesson_total - sc.count_lesson_complete) AS remaining_lessons FROM class_student cs LEFT JOIN student s ON cs.student_id = s.id AND s.deleted = 0 LEFT JOIN course c ON cs.consume_course_id = c.id AND c.deleted = 0 left JOIN user u ON s.user_id = u.id LEFT JOIN student_course sc ON s.id = sc.student_id AND sc.deleted = 0
cs.deleted = 0 AND cs.class_id = #{classId}
AND s.name LIKE CONCAT('%', #{query.studentName}, '%')
AND s.gender = #{query.gender}
ORDER BY cs.add_time DESC
